enum ClockOrder { before, after, equal, concurrent }

ClockOrder compareClocks(
  Map<String, int> left,
  Map<String, int> right,
) {
  var less = false;
  var greater = false;
  for (final actor in left.keys) {
    final leftValue = left[actor]!;
    final rightValue = right[actor] ?? leftValue;
    if (leftValue < rightValue) less = true;
    if (leftValue > rightValue) greater = true;
  }
  if (less && greater) return ClockOrder.concurrent;
  if (less) return ClockOrder.before;
  if (greater) return ClockOrder.after;
  return ClockOrder.equal;
}

