import 'vector_clock.dart';

class SyncRecord {
  SyncRecord({
    required this.id,
    required this.value,
    required this.deleted,
    required this.modifiedAt,
    required this.deviceId,
    required Map<String, int> clock,
  }) : clock = Map.unmodifiable(clock);

  final String id;
  final String value;
  final bool deleted;
  final int modifiedAt;
  final String deviceId;
  final Map<String, int> clock;

  SyncRecord withClock(Map<String, int> joined) => SyncRecord(
        id: id,
        value: value,
        deleted: deleted,
        modifiedAt: modifiedAt,
        deviceId: deviceId,
        clock: joined,
      );
}

SyncRecord resolveRecord(SyncRecord local, SyncRecord remote) {
  final order = compareClocks(local.clock, remote.clock);
  if (order == ClockOrder.before) return remote;
  if (order == ClockOrder.after || order == ClockOrder.equal) return local;
  if (local.modifiedAt != remote.modifiedAt) {
    return local.modifiedAt > remote.modifiedAt ? local : remote;
  }
  return local.deviceId.compareTo(remote.deviceId) <= 0 ? local : remote;
}

