import 'merge_policy.dart';

class SyncEngine {
  SyncEngine(Iterable<SyncRecord> initial)
      : records = {for (final record in initial) record.id: record};

  final Map<String, SyncRecord> records;

  void applyRemote(SyncRecord remote) {
    final local = records[remote.id];
    if (local == null) {
      records[remote.id] = remote;
      return;
    }
    records[remote.id] = resolveRecord(local, remote);
  }
}

