import '../lib/merge_policy.dart';
import '../lib/sync_engine.dart';
import '../lib/vector_clock.dart';

void check(bool condition, String message) {
  if (!condition) throw StateError(message);
}

void main() {
  check(
    compareClocks({'phone': 1}, {'phone': 2}) == ClockOrder.before,
    'ordered clock comparison failed',
  );
  final local = SyncRecord(
    id: 'n1',
    value: 'draft',
    deleted: false,
    modifiedAt: 10,
    deviceId: 'phone',
    clock: {'phone': 1},
  );
  final remote = SyncRecord(
    id: 'n1',
    value: 'published',
    deleted: false,
    modifiedAt: 20,
    deviceId: 'phone',
    clock: {'phone': 2},
  );
  final engine = SyncEngine([local]);
  engine.applyRemote(remote);
  check(engine.records['n1']!.value == 'published', 'newer edit was lost');
}
